function shiftFooter() {
    /*var headerHeight = /*$('header').outerHeight() 0;*/
    var mainHeight = $('#content').outerHeight();
    var footerHeight = $('#footer').outerHeight();
    var viewportHeight = $(window).height();

    if ((/*headerHeight +*/ mainHeight + footerHeight) < viewportHeight) {
        var marginTop = viewportHeight - (/*headerHeight +*/ mainHeight + footerHeight);
        $('#footer').css('margin-top', marginTop + 'px');
    } else {
        $('#footer').css('margin-top', '0');
    }
}

function screen_resize() {

    if($(window).outerWidth() <= 576 )
    {
        $('#sidebar').removeClass('active');
        $('#content').removeClass('active');
    }
}

function fix_account_container(offset = 100) {

    if($('.fix-account-container').length > 0 && $(window).scrollTop() >= offset)
    {
        // alert('aa');

        if($('#content').hasClass('active'))
        {
            $('#fixAccountClick').addClass('active');
            $('.fix-account-container').addClass('sticky-with-sidebar');
            $('.fix-account-container').removeClass('sticky');
        }
        else
        {
            $('#fixAccountClick').addClass('active');
            $('.fix-account-container').removeClass('sticky-with-sidebar');
            $('.fix-account-container').addClass('sticky');
        }
    }
    else
    {
        $('#fixAccountClick').removeClass('active down-arrow');
        $('.fix-account-container').removeClass('sticky-with-sidebar short-container');
        $('.fix-account-container').removeClass('sticky');
    }

}

function check_sub_menu(ul_sub) {

    if(!$(ul_sub).hasClass('show-sub-menu'))
    {
        let c_ul_height = 0;

        $(ul_sub).find('li').each(function(i, obj) {
            c_ul_height += $(obj).outerHeight();
        });
        
        $(ul_sub).parent().addClass('active');
        $(ul_sub).addClass('show-sub-menu');
        $(ul_sub).css({ height: c_ul_height.toFixed(2) + 'px'});
    }
    else
    {
        $(ul_sub).parent().removeClass('active');
        $(ul_sub).removeClass('show-sub-menu');
        $(ul_sub).removeAttr('style');
    }
}

function table_excel_export(table_id, file_name) {

    let tableObj;

    if($('#' + table_id).length > 0)
        tableObj = "#" + table_id;
    else if($('.' + table_id).length > 0)
        tableObj = "." + table_id;

    if(tableObj !== null)
    {
        var table2excel = new Table2Excel({
            defaultFileName: file_name
        });

	    table2excel.export(document.querySelectorAll(tableObj));
    }
}

$(document).ready(function() {

    var tooltipTriggerList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));
    
    var tooltipList = tooltipTriggerList.map(function (tooltipTriggerEl) {
        return new bootstrap.Tooltip(tooltipTriggerEl);
    });

    screen_resize(); //function call
    shiftFooter(); //function call
    fix_account_container(); //function call

    $(window).on('resize', function() {
        screen_resize(); //function call
        shiftFooter(); //function call
        fix_account_container(); //function call
    });

    $(document).on('scroll', function() {
        fix_account_container(); //function call
    });

    if($('#menu_ham').length > 0)
    {
        $('#menu_ham').on('click', function() {

            if($('#sidebar').hasClass('active'))
            {
                $('#sidebar').removeClass('active');
                $('#content').removeClass('active');
            }
            else
            {
                $('#sidebar').addClass('active');
                $('#content').addClass('active');
            }

            fix_account_container(); //function call
        });
    }

    if($('#sidebar #menu').length > 0 && $('#sidebar #menu .sub-menu').length > 0)
    {
        //check and open drop down
        $('#sidebar #menu .sub-menu').each(function(i, obj) {

            if($(this).hasClass('active'))
                check_sub_menu($(this).find('ul'));
        });

        $('#sidebar #menu .sub-menu').on('click', function() {

            let ul_sub = $(this).find('ul');

            //function call
            check_sub_menu($(this).find('ul'));
        });
    }

    if($('#profile_info').length > 0)
    {
        let hoverOrClick = function () {

            if($('#profile_info_container').attr('style'))
                $('#profile_info_container').removeAttr('style');
            else
                $('#profile_info_container').fadeIn();
        }
        
        $('#profile_info').click(hoverOrClick)/*.hover(hoverOrClick)*/;
    }

    if($('.date_cls').length > 0)
        $(".date_cls").datepicker({format:"yyyy-mm-dd",orientation:"bottom"});

    if($('#start_date').length > 0)
        $("#start_date").datepicker({format:"yyyy-mm-dd",orientation:"bottom"});

    if($('#end_date').length > 0)
        $("#end_date").datepicker({format:"yyyy-mm-dd",orientation:"bottom"});

    if($('.select2search').length > 0)
		$('.select2search').select2();

    if($('#checkAllCheckboxes').length > 0 && $('.multi-checkbox-ids').length > 0)
    {
        $('#checkAllCheckboxes').on('click', function() {
            
            if($(this).attr('data-isChecked') == undefined)
            {
                $(this).attr('data-isChecked', 1);
                $('.multi-checkbox-ids').prop('checked', 1);
            }
            else
            {
                $(this).removeAttr('data-isChecked');
                $('.multi-checkbox-ids').prop('checked', 0);
            }
        });
    }

    if( $('.multi-checkbox-check-form').length > 0 && 
        $('.multi-checkbox-ids').length > 0 && 
        $('#multi_type_check').length > 0 )
    {
        $('.multi-checkbox-check-form').on('submit', function(e) {
            
            // e.preventDefault();

            checkboxValues = $('.multi-checkbox-ids:checked').map(function() {
                return this.value;
            }).get().join(',');

            $('#multi_type_check').val(checkboxValues);

            // return false;
        });
    }

    if($('#resetBtn') .length > 0)
    {
        $('#resetBtn').on('click', function() 
        {
            window.location.href = window.location.href;              
        });   
    }

    if ($('.show-hide-content').length > 0 && $('.show-hide-content-container').length > 0) {

        $('.show-hide-content').on('click', function() {
            
            const $container = $(this).closest('div').find('.show-hide-content-container');
    
            if ($(this).html() === 'Show More »') {
                $(this).html('Hide &raquo;');
                $container.css({ 'height': 'auto' });
            } else {
                $(this).html('Show More &raquo;');
                $container.css({ 'height': $container.data('height') + 'px' });
            }
        });
    }

    $("#filterBtn").on("click", function () 
    {
        var filterCriteria = {}; // Object to store filter criteria for each dropdown

        // Iterate over each dropdown
        $(".filter_dropdown").each(function () {

            var filterVal = $(this).val();

            if (filterVal !== "") {
                var tdIndex = $(this).data("sort");
                var filterText = $(this).find("option:selected").text();
                filterCriteria[tdIndex] = filterText; // Store filter criteria for this dropdown
            }
        });

        // Loop through each table row
        $("#dataTable tbody tr").each(function () {

            var showRow = true; // Flag to determine if the row should be shown

            // Iterate over filter criteria for each dropdown
            for (var tdIndex in filterCriteria) 
            {
                var filterText = filterCriteria[tdIndex];

                var rowFirstColumnValue = $(this).find("td:eq(" + tdIndex + ")").text();

                // Check if the first column value matches the selected value or if "all" is selected
                if (rowFirstColumnValue !== filterText) {
                    showRow = false; // If any filter condition fails, hide the row
                    break; // No need to check further, exit loop
                }
            }
            
            if (showRow) {
                $(this).show(); // Show row
            } else {
                $(this).hide(); // Hide row
            }
        });
    });


    if($('#fixAccountClick').length > 0) {
        $('#fixAccountClick').on('click', function() {
            $('.fix-account-container').toggleClass('short-container');

            if($('.fix-account-container').hasClass('short-container'))
                $(this).addClass('down-arrow');
            else
                $(this).removeClass('down-arrow');
        });
    }
});
